
(function(){'use strict';var toggle=document.querySelector('.nav-toggle');var nav=document.getElementById('primary-nav');var mq=window.matchMedia('(min-width: 768px)');if(!toggle||!nav){return}
document.documentElement.classList.add('nav-ready');function setOpen(open){toggle.setAttribute('aria-expanded',open?'true':'false');nav.setAttribute('data-collapsed',open?'false':'true')}
setOpen(mq.matches);toggle.addEventListener('click',function(){setOpen(toggle.getAttribute('aria-expanded')!=='true')});nav.addEventListener('keydown',function(e){if('Escape'===e.key&&!mq.matches){setOpen(!1);toggle.focus()}});mq.addEventListener('change',function(e){setOpen(e.matches)})})();window.addEventListener('load',function(){if(typeof AOS!=='undefined'){AOS.init({duration:600,once:!0,offset:80,})}});


